  1→//! Browser instance pool management.
  2→
  3→use std::{
  4→    collections::HashMap,
  5→    path::PathBuf,
  6→    sync::Arc,
  7→    time::{Duration, Instant},
  8→};
  9→
 10→use {
 11→    chromiumoxide::{
 12→        Browser, BrowserConfig as CdpBrowserConfig, Page,
 13→        cdp::browser_protocol::emulation::SetDeviceMetricsOverrideParams, handler::HandlerConfig,
 14→    },
 15→    futures::StreamExt,
 16→    sysinfo::System,
 17→    tokio::sync::{Mutex, RwLock},
 18→    tracing::{debug, info, warn},
 19→};
 20→
 21→use crate::{
 22→    container::{BrowserContainer, browserless_session_timeout_ms},
 23→    error::Error,
 24→    types::{BrowserConfig, BrowserPreference},
 25→};
 26→
 27→pub(crate) const MAX_BROWSER_INSTANCE_LIFETIME: Duration = Duration::from_secs(30 * 60);
 28→
 29→/// Get current system memory usage as a percentage (0-100).
 30→fn get_memory_usage_percent() -> u8 {
 31→    let mut sys = System::new();
 32→    sys.refresh_memory();
 33→
 34→    let total = sys.total_memory();
 35→    if total == 0 {
 36→        return 0;
 37→    }
 38→
 39→    let used = sys.used_memory();
 40→    let percent = (used as f64 / total as f64 * 100.0) as u8;
 41→    percent.min(100)
 42→}
 43→
 44→/// Returns memory-saving Chrome flags when `total_mb` is below `threshold_mb`.
 45→///
 46→/// Returns an empty slice when the threshold is 0 (disabled) or when the system
 47→/// has enough memory.
 48→#[must_use]
 49→pub(crate) fn low_memory_chrome_args(total_mb: u64, threshold_mb: u64) -> &'static [&'static str] {
 50→    if threshold_mb == 0 || total_mb >= threshold_mb {
 51→        return &[];
 52→    }
 53→    &[
 54→        "--single-process",
 55→        "--renderer-process-limit=1",
 56→        "--js-flags=--max-old-space-size=128",
 57→    ]
 58→}
 59→
 60→/// A pooled browser instance with one or more pages.
 61→struct BrowserInstance {
 62→    browser: Browser,
 63→    pages: HashMap<String, Page>,
 64→    last_used: Instant,
 65→    /// When this instance was first created. Used to enforce a hard TTL that
 66→    /// prevents Chromium memory leaks from accumulating in long-lived instances.
 67→    created_at: Instant,
 68→    /// Whether this instance is running in sandbox mode.
 69→    #[allow(dead_code)]
 70→    sandboxed: bool,
 71→    /// Container for sandboxed instances (None for host browser).
 72→    #[allow(dead_code)]
 73→    container: Option<BrowserContainer>,
 74→}
 75→
 76→/// Pool of browser instances for reuse.
 77→pub struct BrowserPool {
 78→    config: BrowserConfig,
 79→    instances: RwLock<HashMap<String, Arc<Mutex<BrowserInstance>>>>,
 80→    #[cfg(feature = "metrics")]
 81→    active_count: std::sync::atomic::AtomicUsize,
 82→}
 83→
 84→impl BrowserPool {
 85→    /// Create a new browser pool with the given configuration.
 86→    pub fn new(config: BrowserConfig) -> Self {
 87→        Self {
 88→            config,
 89→            instances: RwLock::new(HashMap::new()),
 90→            #[cfg(feature = "metrics")]
 91→            active_count: std::sync::atomic::AtomicUsize::new(0),
 92→        }
 93→    }
 94→
 95→    /// Get or create a browser instance for the given session ID.
 96→    /// Returns the session ID for the browser instance.
 97→    ///
 98→    /// The `sandbox` parameter determines whether to run the browser in a
 99→    /// Docker container (true) or on the host (false). This is set when
100→    /// creating a new session and cannot be changed for existing sessions.
101→    pub async fn get_or_create(
102→        &self,
103→        session_id: Option<&str>,
104→        sandbox: bool,
105→        browser: Option<BrowserPreference>,
106→    ) -> Result<String, Error> {
107→        // Treat empty string as None (generate new session ID)
108→        let session_id = session_id.filter(|s| !s.is_empty());
109→
110→        // Check if we have an existing instance
111→        if let Some(sid) = session_id {
112→            let instances = self.instances.read().await;
113→            if instances.contains_key(sid) {
114→                debug!(session_id = sid, "reusing existing browser instance");
115→                return Ok(sid.to_string());
116→            }
117→        }
118→
119→        // Check pool capacity using memory-based limits
120→        {
121→            // If max_instances is set (> 0), enforce it as a hard limit
122→            if self.config.max_instances > 0 {
123→                let instances = self.instances.read().await;
124→                if instances.len() >= self.config.max_instances {
125→                    drop(instances);
126→                    self.cleanup_idle().await;
127→
128→                    let instances = self.instances.read().await;
129→                    if instances.len() >= self.config.max_instances {
130→                        return Err(Error::PoolExhausted);
131→                    }
132→                }
133→            }
134→
135→            // Check memory usage - block new instances if above threshold
136→            let memory_percent = get_memory_usage_percent();
137→            if memory_percent >= self.config.memory_limit_percent {
138→                // Try to clean up idle instances first
139→                self.cleanup_idle().await;
140→
141→                // Re-check memory after cleanup
142→                let memory_after = get_memory_usage_percent();
143→                if memory_after >= self.config.memory_limit_percent {
144→                    warn!(
145→                        memory_usage = memory_after,
146→                        threshold = self.config.memory_limit_percent,
147→                        "blocking new browser instance due to high memory usage"
148→                    );
149→                    return Err(Error::PoolExhausted);
150→                }
151→            }
152→        }
153→
154→        // Create new instance
155→        let sid = session_id
156→            .map(String::from)
157→            .unwrap_or_else(generate_session_id);
158→
159→        let instance = self.launch_browser(&sid, sandbox, browser).await?;
160→        let instance = Arc::new(Mutex::new(instance));
161→
162→        {
163→            let mut instances = self.instances.write().await;
164→            instances.insert(sid.clone(), instance);
165→        }
166→
167→        #[cfg(feature = "metrics")]
168→        {
169→            self.active_count
170→                .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
171→            moltis_metrics::gauge!(moltis_metrics::browser::INSTANCES_ACTIVE)
172→                .set(self.active_count.load(std::sync::atomic::Ordering::Relaxed) as f64);
173→            moltis_metrics::counter!(moltis_metrics::browser::INSTANCES_CREATED_TOTAL).increment(1);
174→        }
175→
176→        let mode = if sandbox {
177→            "sandboxed"
178→        } else {
179→            "host"
180→        };
181→        info!(session_id = sid, mode, "launched new browser instance");
182→        Ok(sid)
183→    }
184→
185→    /// Get the page for a session, creating one if needed.
186→    pub async fn get_page(&self, session_id: &str) -> Result<Page, Error> {
187→        let instances = self.instances.read().await;
188→        let instance = instances.get(session_id).ok_or(Error::ElementNotFound(0))?;
189→
190→        let mut inst = instance.lock().await;
191→        inst.last_used = Instant::now();
192→
193→        // Get or create the main page
194→        if let Some(page) = inst.pages.get("main") {
195→            debug!(session_id, "reusing existing page");
196→            return Ok(page.clone());
197→        }
198→
199→        // Create a new page
200→        let page = inst
201→            .browser
202→            .new_page("about:blank")
203→            .await
204→            .map_err(|e| Error::LaunchFailed(e.to_string()))?;
205→
206→        // Explicitly set viewport on page to ensure it matches config
207→        // (browser-level viewport may not always be applied to new pages)
208→        let viewport_cmd = SetDeviceMetricsOverrideParams::builder()
209→            .width(self.config.viewport_width)
210→            .height(self.config.viewport_height)
211→            .device_scale_factor(self.config.device_scale_factor)
212→            .mobile(false)
213→            .build()
214→            .map_err(|e| Error::Cdp(format!("invalid viewport params: {e}")))?;
215→
216→        if let Err(e) = page.execute(viewport_cmd).await {
217→            warn!(session_id, error = %e, "failed to set page viewport");
218→        }
219→
220→        info!(
221→            session_id,
222→            viewport_width = self.config.viewport_width,
223→            viewport_height = self.config.viewport_height,
224→            device_scale_factor = self.config.device_scale_factor,
225→            "created new page with viewport"
226→        );
227→
228→        inst.pages.insert("main".to_string(), page.clone());
229→        Ok(page)
230→    }
231→
232→    /// Close a specific browser session.
233→    pub async fn close_session(&self, session_id: &str) -> Result<(), Error> {
234→        let instance = {
235→            let mut instances = self.instances.write().await;
236→            instances.remove(session_id)
237→        };
238→
239→        if let Some(instance) = instance {
240→            let inst = instance.lock().await;
241→            // Pages are closed when browser is dropped
242→            drop(inst);
243→
244→            #[cfg(feature = "metrics")]
245→            {
246→                self.active_count
247→                    .fetch_sub(1, std::sync::atomic::Ordering::Relaxed);
248→                moltis_metrics::gauge!(moltis_metrics::browser::INSTANCES_ACTIVE)
249→                    .set(self.active_count.load(std::sync::atomic::Ordering::Relaxed) as f64);
250→                moltis_metrics::counter!(moltis_metrics::browser::INSTANCES_DESTROYED_TOTAL)
251→                    .increment(1);
252→            }
253→
254→            info!(session_id, "closed browser session");
255→        }
256→
257→        Ok(())
258→    }
259→
260→    /// Clean up idle browser instances and instances that have exceeded the
261→    /// hard TTL ([`MAX_BROWSER_INSTANCE_LIFETIME`]). The TTL prevents Chromium
262→    /// memory leaks from accumulating in long-lived browser instances.
263→    pub async fn cleanup_idle(&self) {
264→        let idle_timeout = Duration::from_secs(self.config.idle_timeout_secs);
265→        let now = Instant::now();
266→
267→        let mut to_remove = Vec::new();
268→
269→        {
270→            let instances = self.instances.read().await;
271→            for (sid, instance) in instances.iter() {
272→                if let Ok(inst) = instance.try_lock() {
273→                    let idle = now.duration_since(inst.last_used) > idle_timeout;
274→                    let expired =
275→                        now.duration_since(inst.created_at) > MAX_BROWSER_INSTANCE_LIFETIME;
276→                    if idle || expired {
277→                        if expired {
278→                            info!(
279→                                session_id = sid,
280→                                age_secs = inst.created_at.elapsed().as_secs(),
281→                                "browser instance exceeded max lifetime"
282→                            );
283→                        }
284→                        to_remove.push(sid.clone());
285→                    }
286→                }
287→            }
288→        }
289→
290→        if to_remove.is_empty() {
291→            return;
292→        }
293→
294→        info!(
295→            count = to_remove.len(),
296→            sessions = ?to_remove,
297→            "cleaning up browser sessions"
298→        );
299→
300→        for sid in to_remove {
301→            if let Err(e) = self.close_session(&sid).await {
302→                warn!(session_id = sid, error = %e, "failed to close session");
303→            }
304→        }
305→    }
306→
307→    /// Shut down all browser instances.
308→    pub async fn shutdown(&self) {
309→        let sessions: Vec<String> = {
310→            let instances = self.instances.read().await;
311→            instances.keys().cloned().collect()
312→        };
313→
314→        for sid in sessions {
315→            let _ = self.close_session(&sid).await;
316→        }
317→
318→        info!("browser pool shut down");
319→    }
320→
321→    /// Get the number of active instances.
322→    pub async fn active_count(&self) -> usize {
323→        self.instances.read().await.len()
324→    }
325→
326→    /// Launch a new browser instance.
327→    async fn launch_browser(
328→        &self,
329→        session_id: &str,
330→        sandbox: bool,
331→        browser: Option<BrowserPreference>,
332→    ) -> Result<BrowserInstance, Error> {
333→        if sandbox {
334→            self.launch_sandboxed_browser(session_id).await
335→        } else {
336→            self.launch_host_browser(session_id, browser).await
337→        }
338→    }
339→
340→    /// Launch a browser inside a container (sandboxed mode).
341→    async fn launch_sandboxed_browser(&self, session_id: &str) -> Result<BrowserInstance, Error> {
342→        use crate::container;
343→
344→        // All container operations (CLI checks, image pulls, container start +
345→        // readiness polling) use synchronous `std::process::Command` and
346→        // `std::thread::sleep`.  Run them on the blocking thread-pool so they
347→        // don't stall the tokio event loop.
348→        let image = self.config.sandbox_image.clone();
349→        let prefix = self.config.container_prefix.clone();
350→        let vw = self.config.viewport_width;
351→        let vh = self.config.viewport_height;
352→        let low_mem = self.config.low_memory_threshold_mb;
353→        let session_timeout_ms = browserless_session_timeout_ms(
354→            self.config.idle_timeout_secs,
355→            self.config.navigation_timeout_ms,
356→            MAX_BROWSER_INSTANCE_LIFETIME.as_secs(),
357→        );
358→        let profile_dir = sandbox_profile_dir(self.config.resolved_profile_dir(), session_id);
359→        let container_host = self.config.container_host.clone();
360→
361→        let container = tokio::task::spawn_blocking(move || {
362→            // Check container runtime availability (Docker or Apple Container)
363→            if !container::is_container_available() {
364→                return Err(Error::LaunchFailed(
365→                    "No container runtime available for sandboxed browser. \
366→                     Please install Docker or Apple Container."
367→                        .to_string(),
368→                ));
369→            }
370→
371→            // Ensure the container image is available
372→            let t_image = Instant::now();
373→            container::ensure_image(&image)
374→                .map_err(|e| Error::LaunchFailed(format!("failed to ensure browser image: {e}")))?;
375→            info!(
376→                elapsed_ms = t_image.elapsed().as_millis() as u64,
377→                "browser container image ready"
378→            );
379→
380→            // Create profile directory on host if needed
381→            if let Some(ref dir) = profile_dir
382→                && let Err(e) = std::fs::create_dir_all(dir)
383→            {
384→                warn!(
385→                    path = %dir.display(),
386→                    error = %e,
387→                    "failed to create browser profile directory for container"
388→                );
389→            }
390→
391→            // Start the container (includes readiness polling)
392→            BrowserContainer::start(
393→                &image,
394→                &prefix,
395→                vw,
396→                vh,
397→                low_mem,
398→                session_timeout_ms,
399→                profile_dir.as_deref(),
400→                &container_host,
401→            )
402→            .map_err(|e| Error::LaunchFailed(format!("failed to start browser container: {e}")))
403→        })
404→        .await
405→        .map_err(|e| Error::LaunchFailed(format!("container launch task panicked: {e}")))??;
406→
407→        let ws_url = container.websocket_url();
408→        info!(
409→            session_id,
410→            container_id = container.id(),
411→            ws_url,
412→            "connecting to sandboxed browser"
413→        );
414→
415→        // Connect to the containerized browser with custom timeout
416→        let handler_config = HandlerConfig {
417→            request_timeout: Duration::from_millis(self.config.navigation_timeout_ms),
418→            viewport: Some(chromiumoxide::handler::viewport::Viewport {
419→                width: self.config.viewport_width,
420→                height: self.config.viewport_height,
421→                device_scale_factor: Some(self.config.device_scale_factor),
422→                emulating_mobile: false,
423→                is_landscape: true,
424→                has_touch: false,
425→            }),
426→            ..Default::default()
427→        };
428→
429→        let (browser, mut handler) = Browser::connect_with_config(&ws_url, handler_config)
430→            .await
431→            .map_err(|e| {
432→                Error::LaunchFailed(format!(
433→                    "failed to connect to containerized browser at {}: {}",
434→                    ws_url, e
435→                ))
436→            })?;
437→
438→        // Spawn handler to process browser events
439→        let session_id_clone = session_id.to_string();
440→        tokio::spawn(async move {
441→            while let Some(event) = handler.next().await {
442→                debug!(session_id = session_id_clone, ?event, "browser event");
443→            }
444→            // Handler exits when connection closes - this is normal for idle sessions
445→            debug!(
446→                session_id = session_id_clone,
447→                "sandboxed browser event handler exited (connection closed)"
448→            );
449→        });
450→
451→        info!(session_id, "sandboxed browser connected successfully");
452→
453→        Ok(BrowserInstance {
454→            browser,
455→            pages: HashMap::new(),
456→            last_used: Instant::now(),
457→            created_at: Instant::now(),
458→            sandboxed: true,
459→            container: Some(container),
460→        })
461→    }
462→
463→    /// Launch a browser on the host (non-sandboxed mode).
464→    async fn launch_host_browser(
465→        &self,
466→        session_id: &str,
467→        browser: Option<BrowserPreference>,
468→    ) -> Result<BrowserInstance, Error> {
469→        let requested_browser = browser.unwrap_or_default();
470→
471→        // Detect all installed browser candidates.
472→        let mut detection = crate::detect::detect_browser(self.config.chrome_path.as_deref());
473→        let mut install_attempt: Option<crate::detect::AutoInstallResult> = None;
474→
475→        // Auto-install is always on: if none are installed, try to install one.
476→        if detection.browsers.is_empty() {
477→            let result = crate::detect::auto_install_browser(requested_browser).await;
478→            if result.attempted && result.installed {
479→                info!(details = %result.details, "auto-installed browser on host");
480→            } else if result.attempted {
481→                warn!(details = %result.details, "browser auto-install failed");
482→            } else {
483→                warn!(
484→                    details = %result.details,
485→                    "browser auto-install skipped (installer unavailable)"
486→                );
487→            }
488→            install_attempt = Some(result);
489→            detection = crate::detect::detect_browser(self.config.chrome_path.as_deref());
490→        }
491→
492→        if detection.browsers.is_empty() {
493→            let mut message = format!("No compatible browser found. {}", detection.install_hint);
494→            if let Some(attempt) = install_attempt
495→                && attempt.attempted
496→            {
497→                message.push_str("\n\nAuto-install attempt:\n");
498→                message.push_str(&attempt.details);
499→            }
500→            return Err(Error::LaunchFailed(message));
501→        }
502→
503→        let selected =
504→            match crate::detect::pick_browser(&detection.browsers, Some(requested_browser)) {
505→                Some(browser) => browser,
506→                None => {
507→                    let installed = crate::detect::installed_browser_labels(&detection.browsers);
508→                    let installed_list = if installed.is_empty() {
509→                        "none".to_string()
510→                    } else {
511→                        installed.join(", ")
512→                    };
513→                    return Err(Error::LaunchFailed(format!(
514→                        "requested browser '{}' is not installed. Installed browsers: {}",
515→                        requested_browser, installed_list
516→                    )));
517→                },
518→            };
519→
520→        let mut builder = CdpBrowserConfig::builder();
521→
522→        // with_head() shows the browser window (non-headless mode)
523→        // By default chromiumoxide runs headless, so we only call with_head() when NOT headless
524→        if !self.config.headless {
525→            builder = builder.with_head();
526→        }
527→
528→        info!(
529→            session_id,
530→            viewport_width = self.config.viewport_width,
531→            viewport_height = self.config.viewport_height,
532→            device_scale_factor = self.config.device_scale_factor,
533→            headless = self.config.headless,
534→            "configuring browser viewport"
535→        );
536→
537→        builder = builder
538→            .viewport(chromiumoxide::handler::viewport::Viewport {
539→                width: self.config.viewport_width,
540→                height: self.config.viewport_height,
541→                device_scale_factor: Some(self.config.device_scale_factor),
542→                emulating_mobile: false,
543→                is_landscape: true,
544→                has_touch: false,
545→            })
546→            .request_timeout(Duration::from_millis(self.config.navigation_timeout_ms));
547→
548→        // User agent can be set via Chrome arg instead of builder method
549→        if let Some(ref ua) = self.config.user_agent {
550→            builder = builder.arg(format!("--user-agent={ua}"));
551→        }
552→        builder = builder.chrome_executable(selected.path.clone());
553→
554→        for arg in &self.config.chrome_args {
555→            builder = builder.arg(arg);
556→        }
557→
558→        // Set persistent profile directory if configured
559→        if let Some(ref profile_path) = self.config.resolved_profile_dir() {
560→            if let Err(e) = std::fs::create_dir_all(profile_path) {
561→                warn!(
562→                    path = %profile_path.display(),
563→                    error = %e,
564→                    "failed to create browser profile directory, falling back to ephemeral"
565→                );
566→            } else {
567→                info!(
568→                    path = %profile_path.display(),
569→                    "using persistent browser profile"
570→                );
571→                builder = builder.user_data_dir(profile_path);
572→            }
573→        }
574→
575→        // Additional security/sandbox args for headless
576→        builder = builder
577→            .arg("--disable-gpu")
578→            .arg("--disable-dev-shm-usage")
579→            .arg("--disable-software-rasterizer")
580→            .arg("--no-sandbox")
581→            .arg("--disable-setuid-sandbox");
582→
583→        // Auto-inject low-memory flags on constrained systems
584→        if self.config.low_memory_threshold_mb > 0 {
585→            let mut sys = System::new();
586→            sys.refresh_memory();
587→            let total_mb = sys.total_memory() / (1024 * 1024);
588→            let extra = low_memory_chrome_args(total_mb, self.config.low_memory_threshold_mb);
589→            if !extra.is_empty() {
590→                info!(
591→                    total_mb,
592→                    threshold = self.config.low_memory_threshold_mb,
593→                    "low memory detected, adding constrained Chrome flags"
594→                );
595→                for arg in extra {
596→                    builder = builder.arg(*arg);
597→                }
598→            }
599→        }
600→
601→        let config = builder
602→            .build()
603→            .map_err(|e| Error::LaunchFailed(format!("failed to build browser config: {e}")))?;
604→
605→        let (browser, mut handler) = Browser::launch(config).await.map_err(|e| {
606→            // Include install instructions in launch failure messages
607→            let install_hint = crate::detect::install_instructions();
608→            Error::LaunchFailed(format!("browser launch failed: {e}\n\n{install_hint}"))
609→        })?;
610→
611→        info!(
612→            session_id,
613→            browser = %selected.kind,
614→            path = %selected.path.display(),
615→            "launched host browser executable"
616→        );
617→
618→        // Spawn handler to process browser events
619→        let session_id_clone = session_id.to_string();
620→        tokio::spawn(async move {
621→            while let Some(event) = handler.next().await {
622→                debug!(session_id = session_id_clone, ?event, "browser event");
623→            }
624→        });
625→
626→        Ok(BrowserInstance {
627→            browser,
628→            pages: HashMap::new(),
629→            last_used: Instant::now(),
630→            created_at: Instant::now(),
631→            sandboxed: false,
632→            container: None,
633→        })
634→    }
635→}
636→
637→impl Drop for BrowserPool {
638→    fn drop(&mut self) {
639→        let instances = self.instances.get_mut();
640→        let count = instances.len();
641→        if count > 0 {
642→            info!(
643→                count,
644→                "browser pool dropping, stopping remaining containers"
645→            );
646→        }
647→    }
648→}
