650→/// Generate a random session ID.
651→fn generate_session_id() -> String {
652→    use rand::Rng;
653→    let mut rng = rand::rng();
654→    let id: u64 = rng.random();
655→    format!("browser-{:016x}", id)
656→}
657→
658→/// Sanitize a session identifier to a filesystem-safe single path segment.
659→fn sanitize_session_component(session_id: &str) -> String {
660→    let sanitized: String = session_id
661→        .chars()
662→        .map(|ch| match ch {
663→            'a'..='z' | 'A'..='Z' | '0'..='9' | '-' | '_' => ch,
664→            _ => '_',
665→        })
666→        .collect();
667→
668→    if sanitized.is_empty() {
669→        return "session".to_string();
670→    }
671→
672→    sanitized
673→}
674→
675→/// Derive a per-session sandbox profile directory from a configured profile root.
676→fn sandbox_profile_dir(profile_root: Option<PathBuf>, session_id: &str) -> Option<PathBuf> {
677→    profile_root.map(|root| {
678→        root.join("sandbox")
679→            .join(sanitize_session_component(session_id))
680→    })
681→}
