148→/// A running browser container instance.
149→pub struct BrowserContainer {
150→    /// Container ID or name.
151→    container_id: String,
152→    /// Host port mapped to the container's CDP port.
153→    host_port: u16,
154→    /// Hostname or IP used to connect to the container.
155→    host: String,
156→    /// The image used.
157→    #[allow(dead_code)]
158→    image: String,
159→    /// The container backend being used.
160→    backend: ContainerBackend,
161→}
162→
163→impl BrowserContainer {
164→    /// Start a new browser container using the auto-detected backend.
165→    ///
166→    /// Returns a container instance with the host port for CDP connections.
167→    /// `container_host` is the hostname/IP used to reach the container (e.g.
168→    /// `"127.0.0.1"` on the host, `"host.docker.internal"` from inside Docker).
169→    /// When `profile_dir` is `Some`, the host directory is mounted into the
170→    /// container so that browser profile data persists across sessions.
171→    pub fn start(
172→        image: &str,
173→        container_prefix: &str,
174→        viewport_width: u32,
175→        viewport_height: u32,
176→        low_memory_threshold_mb: u64,
177→        session_timeout_ms: u64,
178→        profile_dir: Option<&std::path::Path>,
179→        container_host: &str,
180→    ) -> Result<Self> {
181→        let backend = detect_backend()?;
182→        Self::start_with_backend(
183→            backend,
184→            image,
185→            container_prefix,
186→            viewport_width,
187→            viewport_height,
188→            low_memory_threshold_mb,
189→            session_timeout_ms,
190→            profile_dir,
191→            container_host,
192→        )
193→    }
194→
195→    /// Start a new browser container with a specific backend.
196→    pub fn start_with_backend(
197→        backend: ContainerBackend,
198→        image: &str,
199→        container_prefix: &str,
200→        viewport_width: u32,
201→        viewport_height: u32,
202→        low_memory_threshold_mb: u64,
203→        session_timeout_ms: u64,
204→        profile_dir: Option<&std::path::Path>,
205→        container_host: &str,
206→    ) -> Result<Self> {
207→        use std::time::Instant;
208→
209→        if !backend.is_available() {
210→            return Err(Error::LaunchFailed(format!(
211→                "{} is not available. Please install it to use sandboxed browser.",
212→                backend.cli()
213→            )));
214→        }
215→
216→        // Find an available port
217→        let host_port = find_available_port()?;
218→
219→        info!(
220→            image,
221→            host_port,
222→            backend = backend.cli(),
223→            "starting browser container"
224→        );
225→
226→        let t0 = Instant::now();
227→        let container_id = match backend {
228→            ContainerBackend::Docker | ContainerBackend::Podman => start_oci_container(
229→                backend,
230→                image,
231→                container_prefix,
232→                host_port,
233→                viewport_width,
234→                viewport_height,
235→                low_memory_threshold_mb,
236→                session_timeout_ms,
237→                profile_dir,
238→            )?,
239→            #[cfg(target_os = "macos")]
240→            ContainerBackend::AppleContainer => start_apple_container(
241→                image,
242→                container_prefix,
243→                host_port,
244→                viewport_width,
245→                viewport_height,
246→                low_memory_threshold_mb,
247→                session_timeout_ms,
248→                profile_dir,
249→            )?,
250→        };
251→
252→        info!(
253→            container_id,
254→            host_port,
255→            backend = backend.cli(),
256→            elapsed_ms = t0.elapsed().as_millis() as u64,
257→            "browser container process started, waiting for Chrome readiness"
258→        );
259→
260→        // Wait for the container to be ready
261→        if let Err(error) = wait_for_ready(container_host, host_port) {
262→            warn!(
263→                container_id,
264→                host_port,
265→                backend = backend.cli(),
266→                error = %error,
267→                "browser container failed readiness check, cleaning up"
268→            );
269→            stop_container_by_id(backend, &container_id);
270→            return Err(error);
271→        }
272→
273→        info!(
274→            container_id,
275→            host_port,
276→            backend = backend.cli(),
277→            total_startup_ms = t0.elapsed().as_millis() as u64,
278→            "browser container ready"
279→        );
280→
281→        Ok(Self {
282→            container_id,
283→            host_port,
284→            host: container_host.to_string(),
285→            image: image.to_string(),
286→            backend,
287→        })
288→    }
289→
290→    /// Get the WebSocket URL for CDP connection.
291→    #[must_use]
292→    pub fn websocket_url(&self) -> String {
293→        // browserless/chrome provides a direct WebSocket endpoint
294→        format!("ws://{}:{}", self.host, self.host_port)
295→    }
296→
297→    /// Get the HTTP URL for health checks.
298→    #[must_use]
299→    pub fn http_url(&self) -> String {
300→        format!("http://{}:{}", self.host, self.host_port)
301→    }
302→
303→    /// Stop and remove the container.
304→    pub fn stop(&self) {
305→        info!(
306→            container_id = %self.container_id,
307→            backend = self.backend.cli(),
308→            "stopping browser container"
309→        );
310→        stop_container_by_id(self.backend, &self.container_id);
311→    }
312→
313→    /// Get the container ID.
314→    #[must_use]
315→    pub fn id(&self) -> &str {
316→        &self.container_id
317→    }
318→
319→    /// Get the backend being used.
320→    #[must_use]
321→    pub fn backend(&self) -> ContainerBackend {
322→        self.backend
323→    }
324→}
