332→/// Path inside the container where the browser profile is mounted.
333→const CONTAINER_PROFILE_PATH: &str = "/data/browser-profile";
334→
335→/// Build the `DEFAULT_LAUNCH_ARGS` env-var value for containerised Chrome.
336→///
337→/// Always includes `--window-size`; appends low-memory flags when the host
338→/// system RAM is below the given threshold. Adds `--user-data-dir` when a
339→/// container-side profile path is provided.
340→fn build_container_launch_args(
341→    viewport_width: u32,
342→    viewport_height: u32,
343→    low_memory_threshold_mb: u64,
344→    container_profile_dir: Option<&str>,
345→    backend: ContainerBackend,
346→) -> String {
347→    use crate::pool::low_memory_chrome_args;
348→
349→    let mut args = vec![format!("--window-size={viewport_width},{viewport_height}")];
350→
351→    if let Some(profile_dir) = container_profile_dir {
352→        args.push(format!("--user-data-dir={profile_dir}"));
353→    }
354→
355→    // Apple Container VMs may not provide /dev/shm reliably; tell Chrome to
356→    // write shared-memory segments to /tmp instead.
357→    #[cfg(target_os = "macos")]
358→    if backend == ContainerBackend::AppleContainer {
359→        args.push("--disable-dev-shm-usage".to_string());
360→    }
361→    #[cfg(not(target_os = "macos"))]
362→    let _ = backend;
363→
364→    if low_memory_threshold_mb > 0 {
365→        let mut sys = sysinfo::System::new();
366→        sys.refresh_memory();
367→        let total_mb = sys.total_memory() / (1024 * 1024);
368→        for flag in low_memory_chrome_args(total_mb, low_memory_threshold_mb) {
369→            args.push((*flag).to_string());
370→        }
371→    }
372→
373→    let joined = args
374→        .iter()
375→        .map(|a| format!("\"{a}\""))
376→        .collect::<Vec<_>>()
377→        .join(",");
378→    format!("DEFAULT_LAUNCH_ARGS=[{joined}]")
379→}
380→
381→/// Compute the browserless container `TIMEOUT` (in ms) from pool lifecycle settings.
382→///
383→/// The result is `max(idle_timeout_secs, max_instance_lifetime_secs)` converted
384→/// to milliseconds, then floored against `navigation_timeout_ms` so that a single
385→/// long navigation cannot exceed the container's own timeout. The final value is
386→/// capped at `max_instance_lifetime_secs * 1000` to prevent disagree­ment with the
387→/// Moltis-side hard TTL when `navigation_timeout_ms` is very large.
388→pub(crate) fn browserless_session_timeout_ms(
389→    idle_timeout_secs: u64,
390→    navigation_timeout_ms: u64,
391→    max_instance_lifetime_secs: u64,
392→) -> u64 {
393→    let ceiling_ms = max_instance_lifetime_secs.saturating_mul(1000);
394→    idle_timeout_secs
395→        .max(max_instance_lifetime_secs)
396→        .saturating_mul(1000)
397→        .max(navigation_timeout_ms)
398→        .min(ceiling_ms)
399→}
400→
401→fn browserless_container_env(session_timeout_ms: u64) -> Vec<String> {
402→    vec![
403→        format!("TIMEOUT={session_timeout_ms}"),
404→        "MAX_CONCURRENT_SESSIONS=1".to_string(),
405→        "PREBOOT_CHROME=true".to_string(),
406→    ]
407→}
408→
409→/// Start a Docker container for the browser.
410→fn start_oci_container(
411→    backend: ContainerBackend,
412→    image: &str,
413→    container_prefix: &str,
414→    host_port: u16,
415→    viewport_width: u32,
416→    viewport_height: u32,
417→    low_memory_threshold_mb: u64,
418→    session_timeout_ms: u64,
419→    profile_dir: Option<&std::path::Path>,
420→) -> Result<String> {
421→    let cli = backend.cli();
422→    let container_name = new_browser_container_name(container_prefix);
423→
424→    let container_profile_dir = profile_dir.map(|_| CONTAINER_PROFILE_PATH);
425→    let launch_args = build_container_launch_args(
426→        viewport_width,
427→        viewport_height,
428→        low_memory_threshold_mb,
429→        container_profile_dir,
430→        backend,
431→    );
432→    let browserless_env = browserless_container_env(session_timeout_ms);
433→
434→    let mut run_args = vec![
435→        "run".to_string(),
436→        "-d".to_string(),
437→        "--rm".to_string(),
438→        "--name".to_string(),
439→        container_name.clone(),
440→        "-p".to_string(),
441→        format!("{}:3000", host_port),
442→        "-e".to_string(),
443→        launch_args,
444→        "--shm-size=2gb".to_string(),
445→    ];
446→
447→    for env in browserless_env {
448→        run_args.push("-e".to_string());
449→        run_args.push(env);
450→    }
451→
452→    // Mount the profile directory if persistence is enabled
453→    if let Some(host_path) = profile_dir {
454→        run_args.push("-v".to_string());
455→        run_args.push(format!(
456→            "{}:{}:rw",
457→            host_path.display(),
458→            CONTAINER_PROFILE_PATH
459→        ));
460→    }
461→
462→    run_args.push(image.to_string());
463→
464→    let output = Command::new(cli)
465→        .args(&run_args)
466→        .output()
467→        .with_context(|| format!("failed to run {cli} command"))?;
468→
469→    if !output.status.success() {
470→        let stderr = String::from_utf8_lossy(&output.stderr);
471→        return Err(Error::LaunchFailed(format!(
472→            "failed to start {cli} container: {}",
473→            stderr.trim()
474→        )));
475→    }
476→
477→    if container_name.is_empty() {
478→        return Err(Error::LaunchFailed(format!(
479→            "{cli} container name is empty"
480→        )));
481→    }
482→
483→    Ok(container_name)
484→}
