514→        container_name.clone(),
515→        "-p".to_string(),
516→        format!("{}:3000", host_port),
517→        "-e".to_string(),
518→        launch_args,
519→        // Chrome requires shared memory for rendering; Docker uses --shm-size=2gb,
520→        // Apple Container doesn't support --shm-size so mount tmpfs at /dev/shm.
521→        "--tmpfs".to_string(),
522→        "/dev/shm".to_string(),
