524→
525→    for env in browserless_env {
526→        container_args.push("-e".to_string());
527→        container_args.push(env);
528→    }
529→
530→    // Mount the profile directory if persistence is enabled
531→    if let Some(host_path) = profile_dir {
532→        container_args.push("-v".to_string());
533→        container_args.push(format!(
534→            "{}:{}",
